{"version":"0.3.1","atoms":[],"cards":[["html",{"html":"<pre><code>const debounce = (fn, ms = 300) => {
  let t;
  return (...a) => {
    clearTimeout(t);
    t = setTimeout(() => fn(...a), ms);
  };
};</code></pre><p>Trailing-edge debounce. For leading-edge, call <code>fn</code> once before starting the timer.</p>"}]],"markups":[],"sections":[[10,0],[1,"p",[]]]}

